package main

import (
	"encoding/json"
	"fmt"
	"go/ast"
	"go/parser"
	"go/token"
	"os"
	"path/filepath"
	"sort"
	"strings"
)

type Implementor struct {
	Repo       string `json:"repo"`
	File       string `json:"file"`
	StructName string `json:"struct_name"`
}

func main() {
	implementors := []Implementor{}

	// Search in kubernetes/api
	apiImplementors := findImplementorsInRepo("/workspace/api", "kubernetes/api")
	implementors = append(implementors, apiImplementors...)

	// Search in kubernetes/apimachinery
	apimachineryImplementors := findImplementorsInRepo("/workspace/apimachinery", "kubernetes/apimachinery")
	implementors = append(implementors, apimachineryImplementors...)

	// Sort by repo, file, struct name
	sort.Slice(implementors, func(i, j int) bool {
		if implementors[i].Repo != implementors[j].Repo {
			return implementors[i].Repo < implementors[j].Repo
		}
		if implementors[i].File != implementors[j].File {
			return implementors[i].File < implementors[j].File
		}
		return implementors[i].StructName < implementors[j].StructName
	})

	// Write to JSON file
	data, err := json.MarshalIndent(implementors, "", "  ")
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error marshaling JSON: %v\n", err)
		os.Exit(1)
	}

	err = os.WriteFile("/workspace/implementors.json", data, 0644)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error writing file: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Found %d runtime.Object implementors\n", len(implementors))
}

func findImplementorsInRepo(repoPath, repoName string) []Implementor {
	var implementors []Implementor

	err := filepath.Walk(repoPath, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return nil
		}

		// Skip vendor, _test, generated files
		if strings.Contains(path, "/vendor/") || strings.Contains(path, "/.") {
			return nil
		}

		if !strings.HasSuffix(path, "types.go") {
			return nil
		}

		// Skip generated files
		if strings.Contains(path, "_generated.go") || strings.Contains(path, "zz_generated") {
			return nil
		}

		// Parse the file
		fset := token.NewFileSet()
		file, err := parser.ParseFile(fset, path, nil, 0)
		if err != nil {
			return nil // Skip files that can't be parsed
		}

		// Find structs with TypeMeta
		for _, decl := range file.Decls {
			genDecl, ok := decl.(*ast.GenDecl)
			if !ok || genDecl.Tok != token.TYPE {
				continue
			}

			for _, spec := range genDecl.Specs {
				typeSpec, ok := spec.(*ast.TypeSpec)
				if !ok {
					continue
				}

				structType, ok := typeSpec.Type.(*ast.StructType)
				if !ok {
					continue
				}

				// Check if this struct has TypeMeta embedded
				hasTypeMeta := hasTypeMetaField(structType)
				if !hasTypeMeta {
					continue
				}

				// Skip *List types
				if strings.HasSuffix(typeSpec.Name.Name, "List") {
					continue
				}

				// Skip internal types (starting with lowercase or private)
				if !isPublic(typeSpec.Name.Name) {
					continue
				}

				// Get relative path
				relPath, err := filepath.Rel(repoPath, path)
				if err != nil {
					relPath = path
				}

				implementors = append(implementors, Implementor{
					Repo:       repoName,
					File:       filepath.ToSlash(relPath),
					StructName: typeSpec.Name.Name,
				})
			}
		}

		return nil
	})

	if err != nil {
		fmt.Fprintf(os.Stderr, "Error walking directory: %v\n", err)
	}

	return implementors
}

func hasTypeMetaField(structType *ast.StructType) bool {
	if structType.Fields == nil {
		return false
	}

	for _, field := range structType.Fields.List {
		// Check for embedded TypeMeta
		if field.Names == nil || len(field.Names) == 0 {
			// This is an embedded field
			switch fieldType := field.Type.(type) {
			case *ast.SelectorExpr:
				// Something like metav1.TypeMeta or v1.TypeMeta
				if ident, ok := fieldType.X.(*ast.Ident); ok {
					if fieldType.Sel.Name == "TypeMeta" {
						return true
					}
					// Also check for patterns like corev1.TypeMeta
					if (ident.Name == "metav1" || ident.Name == "v1" || strings.HasSuffix(ident.Name, "v1")) && fieldType.Sel.Name == "TypeMeta" {
						return true
					}
				}
			case *ast.Ident:
				// Direct reference to TypeMeta (rare)
				if fieldType.Name == "TypeMeta" {
					return true
				}
			}
		}
	}

	return false
}

func isPublic(name string) bool {
	return len(name) > 0 && name[0] >= 'A' && name[0] <= 'Z'
}

